import React, { useMemo, useState } from 'react';
import {
  Button,
  dispatchAppToast,
  LinListTableConfigModal,
  LinPageLayout,
  loadErpListTableConfig,
  saveErpListTableConfig,
  useCatalogTableBusy,
  type ErpListTableConfig,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../store/hooks';
import erp from '../../styles/erpPage.module.css';
import reportStyles from '../../styles/erpReportPage.module.css';

export type ReportFilterItem = {
  testId: string;
  content: React.ReactNode;
};

export type AnalyticsReportShellProps = {
  testId: string;
  pageId: string;
  title: string;
  titleIconClass?: string;
  listTitle?: string;
  loading: boolean;
  hasData: boolean;
  filterItems: ReportFilterItem[];
  onLoad: () => void;
  viewLabel?: string;
  filterMaxWidthPx?: number;
  tabBar?: React.ReactNode;
  emptyMessage?: string;
  chartComingSoonMessage?: string;
  exportPath?: string;
  exportParams?: Record<string, string | number | boolean | undefined>;
  exportFilename?: string;
  children: React.ReactNode;
  /** Dashboard / import tracker — always render body */
  suppressEmptyGate?: boolean;
  /** Hide default Xem button (dashboard) */
  showViewButton?: boolean;
};

const DEFAULT_VIEW = 'Xem';
const DEFAULT_EMPTY = 'Chọn bộ lọc và bấm Xem';
const DEFAULT_CHART = 'Biểu đồ — pilot tiếp theo';

export const AnalyticsReportShell: React.FC<AnalyticsReportShellProps> = ({
  testId,
  pageId,
  title,
  titleIconClass = 'fas fa-file-alt',
  listTitle,
  loading,
  hasData,
  filterItems,
  onLoad,
  viewLabel = DEFAULT_VIEW,
  filterMaxWidthPx = 1000,
  tabBar,
  emptyMessage = DEFAULT_EMPTY,
  chartComingSoonMessage = DEFAULT_CHART,
  exportPath,
  exportParams,
  exportFilename,
  children,
  suppressEmptyGate = false,
  showViewButton = true,
}) => {
  const dispatch = useAppDispatch();
  const [configOpen, setConfigOpen] = useState(false);
  const [tableConfig, setTableConfig] = useState<ErpListTableConfig>(() =>
    loadErpListTableConfig(`${testId}-report-table-config`),
  );
  const { showTableLoading } = useCatalogTableBusy(loading);

  const handleSaveTableConfig = (next: ErpListTableConfig) => {
    setTableConfig(next);
    saveErpListTableConfig(`${testId}-report-table-config`, next);
  };

  const mergedFilterItems = useMemo(() => {
    const items = [...filterItems];
    if (showViewButton) {
      items.push({
        testId: `${testId}-view-btn`,
        content: (
          <Button
            variant="primary"
            onClick={onLoad}
            loading={loading}
            data-testid={`${testId}-view-btn`}
          >
            {viewLabel}
          </Button>
        ),
      });
    }
    return items;
  }, [filterItems, onLoad, loading, testId, viewLabel, showViewButton]);

  const reportToolbar = useMemo(
    () => ({
      testIdPrefix: testId,
      onRefresh: onLoad,
      canChart: hasData,
      onChart: () =>
        dispatchAppToast(dispatch, { message: chartComingSoonMessage, type: 'info' }),
      canPrint: hasData,
      onPrint: () => window.print(),
      onExport:
        hasData && exportPath
          ? () => {
              void import('../../utils/exportExcel').then(({ exportExcel }) =>
                exportExcel(exportPath, exportParams ?? {}, exportFilename ?? `${testId}.xlsx`),
              );
            }
          : undefined,
      onEditConfig: () => setConfigOpen(true),
    }),
    [
      testId,
      onLoad,
      hasData,
      dispatch,
      chartComingSoonMessage,
      exportPath,
      exportParams,
      exportFilename,
    ],
  );

  const listBody = (
    <>
      {tabBar}
      {!showTableLoading && !hasData && !suppressEmptyGate ? (
        <div
          className={`${erp.empty} ${reportStyles.emptyFill}`}
          data-testid={`${testId}-empty`}
        >
          {emptyMessage}
        </div>
      ) : !showTableLoading ? (
        children
      ) : null}
    </>
  );

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-list-page
      data-report-list-page
      data-testid={`${testId}-list`}
    >
      <LinPageLayout
        kind="report"
        testIdPrefix={testId}
        pageId={pageId}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title,
          titleIconClass,
          pageId,
        }}
        reportToolbar={reportToolbar}
        listTitle={listTitle ?? title}
        filterItems={mergedFilterItems}
        filterMaxWidthPx={filterMaxWidthPx}
        showTableLoading={showTableLoading}
        skeletonRows={8}
        modals={(
          <LinListTableConfigModal
            isOpen={configOpen}
            onClose={() => setConfigOpen(false)}
            testIdPrefix={testId}
            config={tableConfig}
            onSave={handleSaveTableConfig}
          />
        )}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

/** Tab switcher — use inside AnalyticsReportShell tabBar */
export const ReportTabBar: React.FC<{
  testId: string;
  tabs: { id: string; label: string }[];
  activeId: string;
  onChange: (id: string) => void;
}> = ({ testId, tabs, activeId, onChange }) => (
  <div className={reportStyles.tabs} data-testid={`${testId}-tabs`}>
    {tabs.map(t => (
      <button
        key={t.id}
        type="button"
        className={activeId === t.id ? reportStyles.tabActive : reportStyles.tab}
        onClick={() => onChange(t.id)}
      >
        {t.label}
      </button>
    ))}
  </div>
);

export const ReportTableWrap: React.FC<{ children: React.ReactNode; testId?: string }> = ({
  children,
  testId,
}) => (
  <div className={reportStyles.tableWrapper}>
    <table className={reportStyles.table} data-testid={testId}>
      {children}
    </table>
  </div>
);
